import{_ as e,o as t,c as r,S as l}from"./chunks/framework.C6RQlTYc.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/16patterns/intro.md","filePath":"直击概念/16patterns/intro.md","lastUpdated":1778207238000}'),i={name:"直击概念/16patterns/intro.md"};function o(n,a,h,s,p,_){return t(),r("div",null,[...a[0]||(a[0]=[l('<blockquote><p>设计模式是软件开发的基本组成部分，它们为常见问题提供了经过验证的典型解决方案。 本版块整理了 <strong>21 种</strong> 最常用的 JavaScript/TypeScript 设计模式，涵盖创建型、结构型、行为型三大类别，均配有生产级伪代码示例和前端实战场景。</p></blockquote><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><h3 id="创建型模式-4-种" tabindex="-1">创建型模式（4 种） <a class="header-anchor" href="#创建型模式-4-种" aria-label="Permalink to &quot;创建型模式（4 种）&quot;">​</a></h3><ul><li>✅ <a href="./s_pn_1-singleton.html">单例模式 Singleton</a> — 全局唯一实例，状态管理/日志/配置</li><li>✅ <a href="./s_pn_2-factory.html">工厂模式 Factory</a> — 封装对象创建逻辑，屏蔽实现细节</li><li>✅ <a href="./s_pn_3-builder.html">建造者模式 Builder</a> — 分步构建复杂对象，链式调用</li><li>✅ <a href="./s_pn_4-prototype.html">原型模式 Prototype</a> — 克隆对象，Object.create / structuredClone</li></ul><h3 id="结构型模式-5-种" tabindex="-1">结构型模式（5 种） <a class="header-anchor" href="#结构型模式-5-种" aria-label="Permalink to &quot;结构型模式（5 种）&quot;">​</a></h3><ul><li>✅ <a href="./s_pn_5-adapter.html">适配器模式 Adapter</a> — 接口转换，统一不同 API 格式</li><li>✅ <a href="./s_pn_6-decorator.html">装饰器模式 Decorator</a> — 动态添加功能，HOC / 日志 / 缓存</li><li>✅ <a href="./s_pn_7-proxy.html">代理模式 Proxy</a> — 控制访问，ES6 Proxy / 懒加载 / 缓存</li><li>✅ <a href="./s_pn_8-facade.html">外观模式 Facade</a> — 封装复杂子系统，提供简洁 API</li><li>✅ <a href="./s_pn_9-composite.html">组合模式 Composite</a> — 树形结构，递归组件 / DOM 操作</li></ul><h3 id="行为型模式-7-种" tabindex="-1">行为型模式（7 种） <a class="header-anchor" href="#行为型模式-7-种" aria-label="Permalink to &quot;行为型模式（7 种）&quot;">​</a></h3><ul><li>✅ <a href="./s_pn_10-observer.html">观察者模式 Observer</a> — 一对多通知，事件监听 / 响应式</li><li>✅ <a href="./s_pn_11-pubsub.html">发布-订阅模式 PubSub</a> — 事件通道解耦，跨模块通信</li><li>✅ <a href="./s_pn_12-strategy.html">策略模式 Strategy</a> — 算法可替换，表单校验 / 支付</li><li>✅ <a href="./s_pn_13-command.html">命令模式 Command</a> — 请求封装，撤销/重做 / 队列</li><li>✅ <a href="./s_pn_14-state.html">状态模式 State</a> — 状态驱动行为，订单流转 / 请求状态</li><li>✅ <a href="./s_pn_15-iterator.html">迭代器模式 Iterator</a> — 遍历集合，Generator / for-of</li><li>✅ <a href="./s_pn_16-chain_of_responsibility.html">责任链模式 Chain of Responsibility</a> — 请求沿链传递，中间件 / 拦截器</li></ul><h3 id="扩展模式-5-种" tabindex="-1">扩展模式（5 种） <a class="header-anchor" href="#扩展模式-5-种" aria-label="Permalink to &quot;扩展模式（5 种）&quot;">​</a></h3><ul><li>✅ <a href="./s_pn_17-flyweight.html">享元模式 Flyweight</a> — 共享减少内存，对象池 / 虚拟列表</li><li>✅ <a href="./s_pn_18-mediator.html">中介者模式 Mediator</a> — 星形通信，聊天室 / 组件协调</li><li>✅ <a href="./s_pn_19-template_method.html">模板方法模式 Template Method</a> — 定义算法骨架，生命周期 / 数据导入</li><li>✅ <a href="./s_pn_20-module.html">模块模式 Module</a> — 私有封装，ES Module / IIFE</li><li>✅ <a href="./s_pn_21-mixin.html">混合模式 Mixin</a> — 功能组合，替代多重继承</li></ul><blockquote><p>部分内容翻译整理自 <a href="https://www.patterns.dev" target="_blank" rel="noreferrer">patterns.dev</a> 及 <a href="https://refactoring.guru" target="_blank" rel="noreferrer">Refactoring Guru</a>，并结合前端实战做了本地化改编。</p></blockquote>',11)])])}const m=e(i,[["render",o]]);export{f as __pageData,m as default};
